package com.seaquake6324.civitas.application;
import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.population.*;import com.seaquake6324.civitas.infrastructure.persistence.PopulationSavedData;import java.util.*;import org.junit.jupiter.api.Test;
class KillCitizenServiceTest{@Test void invasionDeathIsPermanentRevisionedAndDistinctFromOldAge(){PopulationSavedData data=new PopulationSavedData();CitizenRecord living=citizen();data.putCitizen(living);var result=new KillCitizenService().killFromInvasion(data,living.id(),living.revision(),200);assertTrue(result.success());assertFalse(result.citizen().alive());assertEquals(CitizenDeathCause.INVASION,result.citizen().deathCause());assertEquals(200,result.citizen().diedAtTick());assertEquals(CitizenRuntimeState.VIRTUAL,result.citizen().runtimeState());assertFalse(new KillCitizenService().killFromInvasion(data,living.id(),result.citizen().revision(),300).success());}
@Test void starvationDiseaseAndAccidentAreExplicitIrreversibleCauses(){for(CitizenDeathCause cause:List.of(CitizenDeathCause.STARVATION,CitizenDeathCause.DISEASE,CitizenDeathCause.ACCIDENT)){PopulationSavedData data=new PopulationSavedData();CitizenRecord living=citizen();data.putCitizen(living);var result=new KillCitizenService().kill(data,living.id(),living.revision(),400,cause);assertTrue(result.success());assertEquals(cause,result.citizen().deathCause());assertEquals(0,result.citizen().health());assertFalse(new KillCitizenService().kill(data,living.id(),result.citizen().revision(),500,cause).success());}}
@Test void missingCauseCannotCreateAmbiguousDeath(){PopulationSavedData data=new PopulationSavedData();CitizenRecord living=citizen();data.putCitizen(living);assertEquals(KillCitizenService.Failure.INVALID_CAUSE,new KillCitizenService().kill(data,living.id(),living.revision(),100,CitizenDeathCause.NONE).failure());assertTrue(data.citizen(living.id()).orElseThrow().alive());}
private static CitizenRecord citizen(){return new CitizenRecord(UUID.randomUUID(),"Mira","North",CitizenRace.HUMAN,"human_0",Gender.FEMALE,100,0,UUID.randomUUID(),null,null,null,"",100,CitizenNeeds.neutral(),Map.of(),Set.of(),50,0,CitizenRuntimeState.MATERIALIZED,0,70,0,1);}}
